INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('75c66e88-6fec-5c33-a9bb-1e57393809e2', '8e57d228-2375-4684-9b15-7e73584141b6', 'He ___ a new bike yesterday.', '他昨天買了一輛新腳踏車。', 'got', 'made', 'took', 'saw', '表示「得到」或「拿到」的意思。', 'Get it! (拿到它)'),
('50b9718e-bf2a-5479-ba9d-3bd518587f46', '87f4c3a6-4121-46f4-b4f6-c98aecea1972', 'Many students fell asleep ___ the three-hour lecture.', '在這場三小時的講座期間，許多學生睡著了。', 'during', 'despite', 'between', 'towards', 'dur- 表示持續或耐久', 'dur 聯想 duration (期間) → during (在...期間)'),
('33144233-1a85-5535-a5cc-77aef52ed7d6', '4c6c0fcc-cb90-4b1a-88cc-010c3254fef6', 'She wants ___ new bag.', '她想要一個新包包。', 'a', 'the', 'some', 'any', 'a 為不定冠詞，用於單數可數名詞前，表示「一個」。', 'a 像一個小勾，代表「一個」。'),
('28ba5345-fb1f-5bfb-a86b-f92f8297c1e6', '8b3242aa-721e-485b-a282-9f1917c6f65d', 'There is ___ small cat sleeping on the sofa.', '有一隻小貓在沙發上睡覺。', 'a', 'some', 'any', 'each', 'a 為不定冠詞，用於單數可數名詞前，表示「一個」。', 'a 代表 one (一個)。'),
('a5030f10-8ad6-543d-839f-78cd07a0fd42', 'fb317c3c-8446-4ee4-9bfc-798b3e8a0110', 'Please come ___ and have a seat.', '請進來並坐下吧。', 'in', 'out', 'up', 'away', '在此作為副詞，表示進來。', '從外面進入室內的動作。'),
('23134b3e-9ebc-552c-b49a-6b042193f3ee', '825a281c-8ba8-4992-9d3c-d724865fa454', '___ is my favorite song.', '那是我最喜歡的歌。', 'That', 'Someone', 'Everything', 'Nothing', '指示代名詞，用來指代遠處的人或事物。', '用手指指向遠處的東西。');
